{
  "name": "Al-Mizan Legal Tech (UAE)",
  "description": "A comprehensive legal AI suite for UAE law firms including automated drafting, legal research assistant, and document OCR.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppSection {
  DASHBOARD = 'dashboard',
  GENERATOR = 'generator',
  ASSISTANT = 'assistant',
  OCR = 'ocr',
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

export interface DocumentTemplate {
  id: string;
  name: string;
  description: string;
  promptTemplate: string;
}

export interface OcrPage {
  id: string;
  pageNumber: number;
  imageUrl: string;
  extractedText: string;
  isProcessing: boolean;
}

export const UAE_LAWS_CONTEXT = `
You are an expert UAE Legal Consultant AI. 
You have comprehensive knowledge of:
1. UAE Federal Laws (Civil Code, Commercial Code, Penal Code).
2. Dubai Laws and CM decisions.
3. Abu Dhabi Laws.
4. UAE Labour Law (Federal Decree-Law No. 33 of 2021).
5. Corporate Tax Law.

Always answer in professional Legal Arabic. 
When citing laws, be specific about the Article number and Law number.
Disclaimer: You are an AI assistant, not a substitute for a human judge or final legal counsel.
`;

import { GoogleGenAI } from "@google/genai";
import { UAE_LAWS_CONTEXT } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Draft a legal document
export const generateLegalDocument = async (
  docType: string,
  partyA: string,
  partyB: string,
  details: string
): Promise<string> => {
  const prompt = `
    ${UAE_LAWS_CONTEXT}

    Task: Draft a professional ${docType} in Arabic.

    Parties:
    1. First Party: ${partyA}
    2. Second Party: ${partyB}

    Specific Details/Clauses to include:
    ${details}

    Format:
    - Use standard professional legal formatting suitable for UAE Courts or Ministry of Human Resources.
    - Include standard boilerplate clauses for UAE contracts (Governing Law: UAE, Dispute Resolution, etc.).
    - Output ONLY the document text content.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.3, // Low temperature for factual/legal consistency
      }
    });
    return response.text || "حدث خطأ أثناء إنشاء المستند.";
  } catch (error) {
    console.error("Gen Doc Error:", error);
    return "عذراً، حدث خطأ في الاتصال بخدمة الذكاء الاصطناعي.";
  }
};

// Chat with Legal Assistant
export const sendLegalQuery = async (
  history: {role: string, parts: {text: string}[]}[],
  message: string
) => {
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview', // Pro model for better reasoning
      config: {
        systemInstruction: UAE_LAWS_CONTEXT,
      },
      history: history
    });

    const result = await chat.sendMessage({ message });
    return result.text;
  } catch (error) {
    console.error("Chat Error:", error);
    throw error;
  }
};

// OCR - Extract text from image
export const extractTextFromImage = async (base64Image: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image', // Optimized for vision
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image
            }
          },
          {
            text: "Extract all text from this legal document image exactly as it appears in Arabic. Preserve line breaks where possible. Do not summarize, transcribe verbatim."
          }
        ]
      }
    });
    return response.text || "";
  } catch (error) {
    console.error("OCR Error:", error);
    return "فشل استخراج النص من الصورة.";
  }
};

// Summarize/Analyze Document Text
export const analyzeLegalText = async (text: string): Promise<string> => {
  const prompt = `
    ${UAE_LAWS_CONTEXT}

    Task: Analyze the following legal text.
    1. Identify key obligations.
    2. Highlight any risks or unusual clauses under UAE Law.
    3. Suggest missing protective clauses.

    Text to Analyze:
    ${text}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "";
  } catch (error) {
    console.error("Analysis Error:", error);
    return "فشل تحليل النص.";
  }
};

import React from 'react';
import { LayoutDashboard, FileText, Bot, ScanText, Scale } from 'lucide-react';
import { AppSection } from '../types';

interface SidebarProps {
  currentSection: AppSection;
  setSection: (section: AppSection) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentSection, setSection }) => {
  const menuItems = [
    { id: AppSection.DASHBOARD, label: 'لوحة التحكم', icon: LayoutDashboard },
    { id: AppSection.GENERATOR, label: 'صياغة العقود', icon: FileText },
    { id: AppSection.ASSISTANT, label: 'المساعد الذكي', icon: Bot },
    { id: AppSection.OCR, label: 'تحويل المستندات (OCR)', icon: ScanText },
  ];

  return (
    <div className="w-64 bg-navy-900 text-white h-screen flex flex-col shadow-xl sticky top-0">
      <div className="p-6 flex items-center gap-3 border-b border-navy-800">
        <Scale className="w-8 h-8 text-gold-500" />
        <div>
          <h1 className="text-xl font-bold text-gray-100">الميزان</h1>
          <p className="text-xs text-gray-400">للمحاماة والاستشارات</p>
        </div>
      </div>

      <nav className="flex-1 p-4 space-y-2">
        {menuItems.map((item) => {
          const Icon = item.icon;
          const isActive = currentSection === item.id;
          return (
            <button
              key={item.id}
              onClick={() => setSection(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all duration-200 ${
                isActive 
                  ? 'bg-gold-600 text-white shadow-lg shadow-gold-600/20' 
                  : 'text-gray-300 hover:bg-navy-800 hover:text-white'
              }`}
            >
              <Icon className="w-5 h-5" />
              <span className="font-medium">{item.label}</span>
            </button>
          );
        })}
      </nav>

      <div className="p-4 border-t border-navy-800">
        <div className="bg-navy-800 p-3 rounded-lg">
          <p className="text-sm text-gray-300 mb-1">حالة النظام</p>
          <div className="flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
            <span className="text-xs text-green-400">الذكاء الاصطناعي متصل</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState } from 'react';
import { generateLegalDocument } from '../services/geminiService';
import { FileDown, Printer, PenTool, Loader2 } from 'lucide-react';

const DocumentGenerator: React.FC = () => {
  const [docType, setDocType] = useState('عقد عمل (محدد المدة)');
  const [partyA, setPartyA] = useState('');
  const [partyB, setPartyB] = useState('');
  const [details, setDetails] = useState('');
  const [generatedDoc, setGeneratedDoc] = useState('');
  const [loading, setLoading] = useState(false);

  const handleGenerate = async () => {
    if (!partyA || !partyB) return alert("يرجى تعبئة بيانات الأطراف");

    setLoading(true);
    const result = await generateLegalDocument(docType, partyA, partyB, details);
    setGeneratedDoc(result);
    setLoading(false);
  };

  const handleDownload = () => {
    const element = document.createElement("a");
    const file = new Blob([generatedDoc], {type: 'text/plain;charset=utf-8'});
    element.href = URL.createObjectURL(file);
    element.download = `${docType}.txt`;
    document.body.appendChild(element);
    element.click();
  };

  const templates = [
    "عقد عمل (محدد المدة)",
    "عقد عمل (غير محدد المدة)",
    "اتفاقية عدم إفصاح (NDA)",
    "وكالة عامة",
    "عقد تأسيس شركة ذات مسؤولية محدودة",
    "مذكرة تفاهم",
    "إنذار عدلي"
  ];

  return (
    <div className="p-8 max-w-6xl mx-auto h-screen overflow-y-auto">
      <div className="mb-8">
        <h2 className="text-3xl font-bold text-navy-900 mb-2">توليد الوثائق آلياً</h2>
        <p className="text-gray-600">قم بصياغة عقود ومذكرات قانونية متوافقة مع القوانين الإماراتية باستخدام الذكاء الاصطناعي.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Input Form */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 h-fit">
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">نوع الوثيقة</label>
              <select 
                value={docType}
                onChange={(e) => setDocType(e.target.value)}
                className="w-full p-2.5 bg-gray-50 border border-gray-300 rounded-lg focus:ring-2 focus:ring-gold-500 focus:border-gold-500"
              >
                {templates.map(t => <option key={t} value={t}>{t}</option>)}
              </select>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">الطرف الأول (صاحب العمل/الموكل)</label>
                <input 
                  type="text" 
                  value={partyA}
                  onChange={(e) => setPartyA(e.target.value)}
                  className="w-full p-2.5 bg-gray-50 border border-gray-300 rounded-lg focus:ring-2 focus:ring-gold-500"
                  placeholder="مثال: شركة الأفق للتجارة"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">الطرف الثاني (الموظف/الوكيل)</label>
                <input 
                  type="text" 
                  value={partyB}
                  onChange={(e) => setPartyB(e.target.value)}
                  className="w-full p-2.5 bg-gray-50 border border-gray-300 rounded-lg focus:ring-2 focus:ring-gold-500"
                  placeholder="مثال: أحمد محمد علي"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">تفاصيل إضافية / بنود خاصة</label>
              <textarea 
                rows={4}
                value={details}
                onChange={(e) => setDetails(e.target.value)}
                className="w-full p-2.5 bg-gray-50 border border-gray-300 rounded-lg focus:ring-2 focus:ring-gold-500"
                placeholder="أدخل أي شروط خاصة، الرواتب، المدد الزمنية، أو الشروط الجزائية..."
              ></textarea>
            </div>

            <button 
              onClick={handleGenerate}
              disabled={loading}
              className="w-full flex justify-center items-center gap-2 bg-navy-900 hover:bg-navy-800 text-white py-3 rounded-lg font-bold transition-all disabled:opacity-50"
            >
              {loading ? <Loader2 className="animate-spin" /> : <PenTool className="w-5 h-5" />}
              {loading ? 'جاري الصياغة...' : 'إنشاء الوثيقة'}
            </button>
          </div>
        </div>

        {/* Output Preview */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col h-[600px]">
          <div className="p-4 border-b border-gray-200 flex justify-between items-center bg-gray-50 rounded-t-xl">
            <h3 className="font-bold text-gray-700">معاينة المستند</h3>
            <div className="flex gap-2">
              <button 
                onClick={() => window.print()}
                className="p-2 hover:bg-gray-200 rounded-full text-gray-600 tooltip"
                title="طباعة"
              >
                <Printer className="w-5 h-5" />
              </button>
              <button 
                onClick={handleDownload}
                disabled={!generatedDoc}
                className="p-2 hover:bg-gray-200 rounded-full text-gray-600 disabled:opacity-30"
                title="تحميل Word/Text"
              >
                <FileDown className="w-5 h-5" />
              </button>
            </div>
          </div>
          <textarea 
            value={generatedDoc}
            onChange={(e) => setGeneratedDoc(e.target.value)}
            className="flex-1 p-6 w-full resize-none focus:outline-none font-serif leading-relaxed text-lg text-gray-800"
            placeholder="ستظهر الوثيقة المولدة هنا..."
            dir="rtl"
          ></textarea>
        </div>
      </div>
    </div>
  );
};

export default DocumentGenerator;

import React, { useState, useRef, useEffect } from 'react';
import { sendLegalQuery } from '../services/geminiService';
import { ChatMessage } from '../types';
import { Send, Bot, User, AlertTriangle, Sparkles } from 'lucide-react';

const SmartAssistant: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'مرحباً بك. أنا مساعدك القانوني الذكي المختص بالقوانين الإماراتية. يمكنك سؤالي عن القوانين الاتحادية، قوانين العمل، أو طلب تحليل لموقف قانوني معين.',
      timestamp: new Date()
    }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!inputValue.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: inputValue,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsLoading(true);

    try {
        // Prepare history for API
        const history = messages.map(m => ({
            role: m.role,
            parts: [{ text: m.text }]
        }));

      const responseText = await sendLegalQuery(history, userMsg.text);

      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText || "عذراً، لم أتمكن من العثور على إجابة دقيقة.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "حدث خطأ في الاتصال. يرجى المحاولة مرة أخرى.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gray-50">
      <div className="bg-white border-b px-6 py-4 shadow-sm z-10">
        <h2 className="text-xl font-bold text-navy-900 flex items-center gap-2">
          <Sparkles className="text-gold-500 w-5 h-5" />
          المساعد القانوني الذكي (UAE Law)
        </h2>
        <div className="flex items-center gap-2 mt-1 text-xs text-amber-700 bg-amber-50 px-3 py-1 rounded-full w-fit">
            <AlertTriangle className="w-3 h-3" />
            <span>تنبيه: المعلومات المقدمة للأغراض الاسترشادية فقط ولا تغني عن الاستشارة الرسمية.</span>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex items-start gap-4 max-w-3xl ${msg.role === 'user' ? 'mr-auto flex-row-reverse' : ''}`}
          >
            <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ${
              msg.role === 'user' ? 'bg-navy-800 text-white' : 'bg-gold-500 text-white'
            }`}>
              {msg.role === 'user' ? <User className="w-6 h-6" /> : <Bot className="w-6 h-6" />}
            </div>

            <div className={`rounded-2xl p-4 shadow-sm text-base leading-relaxed ${
              msg.role === 'user' 
                ? 'bg-navy-900 text-white rounded-tr-none' 
                : 'bg-white text-gray-800 border border-gray-100 rounded-tl-none'
            }`}>
               {msg.text.split('\n').map((line, i) => (
                 <p key={i} className="mb-2 last:mb-0">{line}</p>
               ))}
               <span className={`text-[10px] block mt-2 opacity-70 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                 {msg.timestamp.toLocaleTimeString('ar-AE', {hour: '2-digit', minute:'2-digit'})}
               </span>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex items-center gap-3 animate-pulse">
             <div className="w-10 h-10 rounded-full bg-gold-200"></div>
             <div className="h-4 w-24 bg-gray-200 rounded"></div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-white border-t border-gray-200">
        <div className="max-w-4xl mx-auto relative">
          <input
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="اسأل عن قانون، اطلب تلخيص قضية، أو استفسر عن إجراء..."
            className="w-full pl-12 pr-4 py-4 bg-gray-100 border-0 rounded-xl focus:ring-2 focus:ring-gold-500 focus:bg-white transition-all"
          />
          <button 
            onClick={handleSend}
            disabled={!inputValue.trim() || isLoading}
            className="absolute left-2 top-2 p-2 bg-navy-900 text-white rounded-lg hover:bg-navy-800 disabled:opacity-50 transition-colors"
          >
            <Send className="w-5 h-5" />
          </button>
        </div>
      </div>
    </div>
  );
};

export default SmartAssistant;

import React, { useState, useRef } from 'react';
import { extractTextFromImage, analyzeLegalText } from '../services/geminiService';
import { OcrPage } from '../types';
import { Upload, FileText, Download, Trash2, Eye, BrainCircuit } from 'lucide-react';

const OCRTool: React.FC = () => {
  const [pages, setPages] = useState<OcrPage[]>([]);
  const [selectedPageId, setSelectedPageId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState('');

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files) {
      const files = Array.from(event.target.files);

      for (const file of files) {
        const reader = new FileReader();
        reader.onloadend = async () => {
          const base64Data = reader.result as string;
          // Clean base64 string for API
          const cleanBase64 = base64Data.split(',')[1];

          const newPage: OcrPage = {
            id: Date.now().toString() + Math.random().toString(),
            pageNumber: pages.length + 1,
            imageUrl: base64Data,
            extractedText: "جاري الاستخراج...",
            isProcessing: true,
          };

          setPages(prev => [...prev, newPage]);
          if (!selectedPageId) setSelectedPageId(newPage.id);

          // Trigger OCR
          const text = await extractTextFromImage(cleanBase64);

          setPages(prev => prev.map(p => 
            p.id === newPage.id 
              ? { ...p, extractedText: text, isProcessing: false } 
              : p
          ));
        };
        reader.readAsDataURL(file);
      }
    }
  };

  const updateText = (id: string, newText: string) => {
    setPages(prev => prev.map(p => p.id === id ? { ...p, extractedText: newText } : p));
  };

  const removePage = (id: string) => {
    setPages(prev => prev.filter(p => p.id !== id));
    if (selectedPageId === id) setSelectedPageId(null);
  };

  const exportAll = (format: 'pdf' | 'doc') => {
    // Simple text export logic for demonstration
    const fullText = pages.map(p => `--- صفحة ${p.pageNumber} ---\n\n${p.extractedText}`).join('\n\n');
    const blob = new Blob([fullText], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `extracted_document.${format === 'doc' ? 'doc' : 'txt'}`;
    a.click();
    if(format === 'pdf') window.print(); // Native print allows PDF save
  };

  const handleAnalysis = async () => {
    if (!selectedPageId) return;
    const page = pages.find(p => p.id === selectedPageId);
    if (!page) return;

    setAnalyzing(true);
    const result = await analyzeLegalText(page.extractedText);
    setAnalysisResult(result);
    setAnalyzing(false);
  };

  const activePage = pages.find(p => p.id === selectedPageId);

  return (
    <div className="h-screen flex flex-col p-6 max-w-7xl mx-auto">
      <div className="flex justify-between items-center mb-6">
        <div>
           <h2 className="text-2xl font-bold text-navy-900">المسح الضوئي واستخراج النصوص</h2>
           <p className="text-gray-500 text-sm">قم برفع صور المستندات لاستخراج النصوص وتحويلها إلى Word/PDF</p>
        </div>
        <div className="flex gap-3">
             <button 
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center gap-2 bg-navy-900 text-white px-4 py-2 rounded-lg hover:bg-navy-800"
            >
              <Upload className="w-4 h-4" />
              رفع مستندات
            </button>
            <input 
              type="file" 
              multiple 
              accept="image/*" 
              className="hidden" 
              ref={fileInputRef} 
              onChange={handleFileUpload}
            />
             <button 
              onClick={() => exportAll('doc')}
              disabled={pages.length === 0}
              className="flex items-center gap-2 bg-white border border-gray-300 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-50 disabled:opacity-50"
            >
              <Download className="w-4 h-4" />
              تصدير Word
            </button>
        </div>
      </div>

      <div className="flex flex-1 gap-6 overflow-hidden">
        {/* Thumbnails Sidebar */}
        <div className="w-48 bg-gray-100 rounded-xl p-4 overflow-y-auto space-y-4 border border-gray-200">
          <h3 className="text-xs font-bold text-gray-500 uppercase">الصفحات</h3>
          {pages.length === 0 && <p className="text-xs text-gray-400 text-center mt-10">لا توجد صفحات</p>}

          {pages.map((page) => (
            <div 
              key={page.id}
              onClick={() => setSelectedPageId(page.id)}
              className={`relative group cursor-pointer border-2 rounded-lg overflow-hidden transition-all ${
                selectedPageId === page.id ? 'border-gold-500 ring-2 ring-gold-200' : 'border-gray-200 hover:border-gray-300'
              }`}
            >
              <img src={page.imageUrl} alt={`Page ${page.pageNumber}`} className="w-full h-32 object-cover" />
              <div className="absolute bottom-0 left-0 right-0 bg-black/60 text-white text-xs p-1 text-center">
