import React, { useState, useRef } from 'react';
import { extractTextFromImage, analyzeLegalText } from '../services/geminiService';
import { OcrPage } from '../types';
import { Upload, FileText, Download, Trash2, Eye, BrainCircuit } from 'lucide-react';

const OCRTool: React.FC = () => {
  const [pages, setPages] = useState<OcrPage[]>([]);
  const [selectedPageId, setSelectedPageId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState('');

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files) {
      const files: File[] = Array.from(event.target.files);

      for (const file of files) {
        const reader = new FileReader();
        reader.onloadend = async () => {
          const base64Data = reader.result as string;
          // Clean base64 string for API
          const cleanBase64 = base64Data.split(',')[1];

          const newPage: OcrPage = {
            id: Date.now().toString() + Math.random().toString(),
            pageNumber: pages.length + 1,
            imageUrl: base64Data,
            extractedText: "جاري الاستخراج...",
            isProcessing: true,
          };

          setPages(prev => [...prev, newPage]);
          if (!selectedPageId) setSelectedPageId(newPage.id);

          // Trigger OCR
          const text = await extractTextFromImage(cleanBase64);

          setPages(prev => prev.map(p => 
            p.id === newPage.id 
              ? { ...p, extractedText: text, isProcessing: false } 
              : p
          ));
        };
        reader.readAsDataURL(file);
      }
    }
  };

  const updateText = (id: string, newText: string) => {
    setPages(prev => prev.map(p => p.id === id ? { ...p, extractedText: newText } : p));
  };

  const removePage = (id: string) => {
    setPages(prev => prev.filter(p => p.id !== id));
    if (selectedPageId === id) setSelectedPageId(null);
  };

  const exportAll = (format: 'pdf' | 'doc') => {
    // Simple text export logic for demonstration
    const fullText = pages.map(p => `--- صفحة ${p.pageNumber} ---\n\n${p.extractedText}`).join('\n\n');
    const blob = new Blob([fullText], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `extracted_document.${format === 'doc' ? 'doc' : 'txt'}`;
    a.click();
    if(format === 'pdf') window.print(); // Native print allows PDF save
  };

  const handleAnalysis = async () => {
    if (!selectedPageId) return;
    const page = pages.find(p => p.id === selectedPageId);
    if (!page) return;

    setAnalyzing(true);
    const result = await analyzeLegalText(page.extractedText);
    setAnalysisResult(result);
    setAnalyzing(false);
  };

  const activePage = pages.find(p => p.id === selectedPageId);

  return (
    <div className="h-screen flex flex-col p-6 max-w-7xl mx-auto">
      <div className="flex justify-between items-center mb-6">
        <div>
           <h2 className="text-2xl font-bold text-navy-900">المسح الضوئي واستخراج النصوص</h2>
           <p className="text-gray-500 text-sm">قم برفع صور المستندات لاستخراج النصوص وتحويلها إلى Word/PDF</p>
        </div>
        <div className="flex gap-3">
             <button 
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center gap-2 bg-navy-900 text-white px-4 py-2 rounded-lg hover:bg-navy-800"
            >
              <Upload className="w-4 h-4" />
              رفع مستندات
            </button>
            <input 
              type="file" 
              multiple 
              accept="image/*" 
              className="hidden" 
              ref={fileInputRef} 
              onChange={handleFileUpload}
            />
             <button 
              onClick={() => exportAll('doc')}
              disabled={pages.length === 0}
              className="flex items-center gap-2 bg-white border border-gray-300 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-50 disabled:opacity-50"
            >
              <Download className="w-4 h-4" />
              تصدير Word
            </button>
        </div>
      </div>

      <div className="flex flex-1 gap-6 overflow-hidden">
        {/* Thumbnails Sidebar */}
        <div className="w-48 bg-gray-100 rounded-xl p-4 overflow-y-auto space-y-4 border border-gray-200">
          <h3 className="text-xs font-bold text-gray-500 uppercase">الصفحات</h3>
          {pages.length === 0 && <p className="text-xs text-gray-400 text-center mt-10">لا توجد صفحات</p>}

          {pages.map((page) => (
            <div 
              key={page.id}
              onClick={() => setSelectedPageId(page.id)}
              className={`relative group cursor-pointer border-2 rounded-lg overflow-hidden transition-all ${
                selectedPageId === page.id ? 'border-gold-500 ring-2 ring-gold-200' : 'border-gray-200 hover:border-gray-300'
              }`}
            >
              <img src={page.imageUrl} alt={`Page ${page.pageNumber}`} className="w-full h-32 object-cover" />
              <div className="absolute bottom-0 left-0 right-0 bg-black/60 text-white text-xs p-1 text-center">
                صفحة {page.pageNumber}
              </div>
              <button 
                onClick={(e) => { e.stopPropagation(); removePage(page.id); }}
                className="absolute top-1 right-1 p-1 bg-red-500 text-white rounded opacity-0 group-hover:opacity-100 transition-opacity"
              >
                <Trash2 className="w-3 h-3" />
              </button>
              {page.isProcessing && (
                <div className="absolute inset-0 bg-white/50 flex items-center justify-center">
                   <div className="animate-spin w-6 h-6 border-2 border-navy-900 border-t-transparent rounded-full"></div>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* Editor Area */}
        <div className="flex-1 bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col overflow-hidden">
           {activePage ? (
             <div className="flex h-full">
               {/* Extracted Text */}
               <div className="flex-1 flex flex-col border-l border-gray-200">
                  <div className="p-3 bg-gray-50 border-b border-gray-200 flex justify-between items-center">
                    <span className="font-bold text-gray-700 flex items-center gap-2">
                      <FileText className="w-4 h-4" /> النص المستخرج
                    </span>
                    <button 
                      onClick={handleAnalysis}
                      disabled={analyzing}
                      className="text-xs flex items-center gap-1 bg-gold-100 text-gold-700 px-2 py-1 rounded hover:bg-gold-200"
                    >
                      <BrainCircuit className="w-3 h-3" />
                      {analyzing ? 'جاري التحليل...' : 'تحليل قانوني للنص'}
                    </button>
                  </div>
                  <textarea 
                    value={activePage.extractedText}
                    onChange={(e) => updateText(activePage.id, e.target.value)}
                    className="flex-1 w-full p-6 resize-none focus:outline-none text-lg leading-loose font-serif"
                    dir="rtl"
                  ></textarea>
               </div>

               {/* Analysis Panel (Conditional) */}
               {analysisResult && (
                 <div className="w-1/3 border-r border-gray-200 bg-gray-50 flex flex-col">
                   <div className="p-3 border-b bg-white font-bold text-navy-900">التحليل الذكي</div>
                   <div className="p-4 overflow-y-auto text-sm space-y-2">
                     {analysisResult.split('\n').map((l, i) => <p key={i}>{l}</p>)}
                   </div>
                   <button onClick={() => setAnalysisResult('')} className="p-2 text-center text-xs text-red-500 hover:bg-red-50">إغلاق</button>
                 </div>
               )}
             </div>
           ) : (
             <div className="h-full flex flex-col items-center justify-center text-gray-400">
                <Eye className="w-16 h-16 mb-4 opacity-20" />
                <p>اختر صفحة لعرض النص وتعديله</p>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

