  const [analysisResult, setAnalysisResult] = useState('');
  const [copied, setCopied] = useState(false);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files) {
      const files: File[] = Array.from(event.target.files);

      for (const file of files) {
        const reader = new FileReader();
        reader.onloadend = async () => {
          const base64Data = reader.result as string;
          // Clean base64 string for API
          const cleanBase64 = base64Data.split(',')[1];

          const newPage: OcrPage = {
            id: Date.now().toString() + Math.random().toString(),
            pageNumber: pages.length + 1,
            imageUrl: base64Data,
            extractedText: "جاري الاستخراج...",
            isProcessing: true,
          };

          setPages(prev => [...prev, newPage]);
          if (!selectedPageId) setSelectedPageId(newPage.id);

          // Trigger OCR
          const text = await extractTextFromImage(cleanBase64);

          setPages(prev => prev.map(p => 
            p.id === newPage.id 
              ? { ...p, extractedText: text, isProcessing: false } 
              : p
          ));
        };
        reader.readAsDataURL(file);
