import { GoogleGenAI } from "@google/genai";
import { KUWAIT_LAWS_CONTEXT } from '../types';

// Helper to get authenticated client dynamically
const getGenAI = () => {
  let apiKey = process.env.API_KEY; // Default env key

  // Try to get key from settings
  try {
    const settingsStr = localStorage.getItem('lawFirmSettings');
    if (settingsStr) {
      const settings = JSON.parse(settingsStr);
      if (settings.apiKey && settings.apiKey.trim() !== '') {
        apiKey = settings.apiKey;
      }
    }
  } catch (e) {
    console.error("Error reading API key from settings", e);
  }

  if (!apiKey) {
    throw new Error("API Key is missing. Please check settings.");
  }

  return new GoogleGenAI({ apiKey });
};

// Draft a legal document
export const generateLegalDocument = async (
  docType: string,
  partyA: string,
  partyB: string,
  details: string,
  courtDetails?: { name: string; caseNumber: string; section: string }
): Promise<string> => {
  const ai = getGenAI();
  const courtContext = courtDetails ? `
    Court Name: ${courtDetails.name}
    Case Number: ${courtDetails.caseNumber}
    Department/Section: ${courtDetails.section}
    Include this court header information at the top of the document in a formal legal layout typical for Kuwaiti courts.
  ` : '';

  const prompt = `
    ${KUWAIT_LAWS_CONTEXT}

    Task: Draft a professional ${docType} in Arabic.

    ${courtContext}

    Parties:
    1. First Party: ${partyA}
    2. Second Party: ${partyB}

    Specific Details/Clauses to include:
    ${details}

    Format:
    - Use standard professional legal formatting suitable for Kuwaiti Courts (e.g. State of Kuwait, Ministry of Justice headers in text).
    - If it's a court memo, begin with "السيد المستشار / رئيس الدائرة ... المحترم".
    - Include standard boilerplate clauses for Kuwaiti contracts/memos (Governing Law: Kuwait, Dispute Resolution: Kuwait Courts).
    - Output ONLY the document text content.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.3, // Low temperature for factual/legal consistency
      }
    });
    return response.text || "حدث خطأ أثناء إنشاء المستند.";
  } catch (error) {
    console.error("Gen Doc Error:", error);
    return "عذراً، حدث خطأ في الاتصال بخدمة الذكاء الاصطناعي. يرجى التأكد من مفتاح API في الإعدادات.";
  }
};

// Chat with Legal Assistant
export const sendLegalQuery = async (
  history: {role: string, parts: {text: string}[]}[],
  message: string
) => {
  try {
    const ai = getGenAI();
    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview', // Pro model for better reasoning
      config: {
        systemInstruction: KUWAIT_LAWS_CONTEXT,
      },
      history: history
    });

    const result = await chat.sendMessage({ message });
    return result.text;
  } catch (error) {
    console.error("Chat Error:", error);
    throw error;
  }
};

// OCR - Extract text from image
export const extractTextFromImage = async (base64Image: string): Promise<string> => {
  try {
    const ai = getGenAI();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image', // Optimized for vision
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image
            }
          },
          {
            text: "Extract all text from this legal document image exactly as it appears in Arabic. Preserve line breaks where possible. Do not summarize, transcribe verbatim."
          }
        ]
      }
    });
    return response.text || "";
  } catch (error) {
    console.error("OCR Error:", error);
    return "فشل استخراج النص من الصورة.";
  }
};

// Transcribe Audio
export const transcribeAudio = async (base64Audio: string): Promise<string> => {
  try {
    const ai = getGenAI();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-native-audio-preview-09-2025',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'audio/mp3', // Generic container, usually works with webm/mp3
              data: base64Audio
            }
          },
          {
            text: "Transcribe the following Arabic audio recording accurately into text. It is a legal context, so be precise."
          }
        ]
      }
    });
    return response.text || "";
  } catch (error) {
    console.error("Audio Transcription Error:", error);
    return "فشل تحويل الصوت إلى نص.";
  }
};

// Summarize/Analyze Document Text
export const analyzeLegalText = async (text: string): Promise<string> => {
  const prompt = `
    ${KUWAIT_LAWS_CONTEXT}

    Task: Analyze the following legal text under Kuwaiti Law.
    1. Identify key obligations.
    2. Highlight any risks or unusual clauses under Kuwait Civil/Commercial Codes.
    3. Suggest missing protective clauses.

    Text to Analyze:
    ${text}
  `;

  try {
    const ai = getGenAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "";
  } catch (error) {
    console.error("Analysis Error:", error);
    return "فشل تحليل النص.";
  }
};

