              className="hidden" 
              ref={fileInputRef} 
              onChange={handleFileUpload}
            />

            {/* Camera Button */}
            <button 
              onClick={() => cameraInputRef.current?.click()}
              className="flex items-center gap-2 bg-gray-100 text-navy-900 px-4 py-2 rounded-lg hover:bg-gray-200 transition-colors border border-gray-300"
            >
              <Camera className="w-4 h-4" />
              <span>الكاميرا</span>
            </button>
            <input 
              type="file" 
              accept="image/*" 
              capture="environment" 
              className="hidden" 
              ref={cameraInputRef} 
              onChange={handleFileUpload}
            />

            {/* Microphone Button */}
            <button 
              onClick={isRecording ? handleStopRecording : handleStartRecording}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all border font-bold ${
                isRecording 
                  ? 'bg-red-50 text-red-600 border-red-200 animate-pulse' 
                  : 'bg-gold-50 text-gold-700 border-gold-200 hover:bg-gold-100'
              }`}
            >
              {isRecording ? <Square className="w-4 h-4 fill-current" /> : <Mic className="w-4 h-4" />}
              <span>{isRecording ? 'إيقاف التسجيل' : 'التسجيل بصوتى'}</span>
            </button>
        </div>
      </div>

      <div className="flex flex-1 gap-6 overflow-hidden print:hidden">
        {/* Thumbnails Sidebar */}
        <div className="w-48 bg-gray-100 rounded-xl p-4 overflow-y-auto space-y-4 border border-gray-200 flex-shrink-0">
          <h3 className="text-xs font-bold text-gray-500 uppercase">العناصر</h3>
          {pages.length === 0 && <p className="text-xs text-gray-400 text-center mt-10">لا توجد عناصر</p>}

          {pages.map((page) => (
            <div 
              key={page.id}
              onClick={() => setSelectedPageId(page.id)}
              className={`relative group cursor-pointer border-2 rounded-lg overflow-hidden transition-all bg-white ${
                selectedPageId === page.id ? 'border-gold-500 ring-2 ring-gold-200' : 'border-gray-200 hover:border-gray-300'
              }`}
            >
              <img src={page.imageUrl} alt={`Page ${page.pageNumber}`} className="w-full h-32 object-contain bg-gray-50" />
              <div className="absolute bottom-0 left-0 right-0 bg-black/60 text-white text-xs p-1 text-center">
                {page.imageUrl.includes('svg') ? 'تسجيل صوتي' : `صفحة ${page.pageNumber}`}
              </div>
              <button 
                onClick={(e) => { e.stopPropagation(); removePage(page.id); }}
                className="absolute top-1 right-1 p-1 bg-red-500 text-white rounded opacity-0 group-hover:opacity-100 transition-opacity"
              >
                <Trash2 className="w-3 h-3" />
              </button>
              {page.isProcessing && (
                <div className="absolute inset-0 bg-white/50 flex items-center justify-center">
                   <div className="animate-spin w-6 h-6 border-2 border-navy-900 border-t-transparent rounded-full"></div>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* Editor Area */}
        <div className="flex-1 bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col overflow-hidden">
           {activePage ? (
             <div className="flex h-full">
               {/* Extracted Text */}
               <div className="flex-1 flex flex-col border-l border-gray-200">
                  <div className="p-3 bg-gray-50 border-b border-gray-200 flex flex-wrap justify-between items-center gap-2">
                    <div className="flex items-center gap-2">
                         <span className="font-bold text-gray-700 flex items-center gap-2">
                            <FileText className="w-4 h-4" /> النص المستخرج
                         </span>
                         <button 
                            onClick={handleAnalysis}
                            disabled={analyzing}
                            className="text-xs flex items-center gap-1 bg-gold-100 text-gold-700 px-2 py-1 rounded hover:bg-gold-200 ml-2"
                            title="تحليل قانوني للنص باستخدام الذكاء الاصطناعي"
                          >
                            <BrainCircuit className="w-3 h-3" />
                            {analyzing ? 'جاري التحليل...' : 'تحليل'}
                          </button>
                    </div>

                    <div className="flex items-center gap-2">
                        {/* Copy Button */}
                        <button 
                            onClick={handleCopy}
                            className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-gray-100 text-gray-600 hover:bg-gray-200 hover:text-navy-900 text-xs font-bold transition-all"
                            title="نسخ النص"
                        >
                            {copied ? <Check className="w-3.5 h-3.5 text-green-600" /> : <Copy className="w-3.5 h-3.5" />}
                            {copied ? 'تم النسخ' : 'نسخ'}
                        </button>

                         {/* Print Button */}
                        <button 
                            onClick={handlePrint}
                            className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-gray-100 text-gray-600 hover:bg-gray-200 hover:text-navy-900 text-xs font-bold transition-all"
                            title="طباعة النص"
                        >
                            <Printer className="w-3.5 h-3.5" />
                            طباعة
                        </button>

                        <div className="w-px h-5 bg-gray-300 mx-1"></div>

                         {/* Export Buttons */}
                        <div className="flex bg-gray-100 rounded-lg p-0.5">
                           <button 
                              onClick={() => handleExport('doc')}
                              className="px-2 py-1 rounded hover:bg-white hover:shadow-sm text-[10px] font-bold text-gray-600 flex items-center gap-1"
                              title="تصدير كملف Word"
                           >
                              Word
                           </button>
                           <button 
                              onClick={() => handleExport('txt')}
                              className="px-2 py-1 rounded hover:bg-white hover:shadow-sm text-[10px] font-bold text-gray-600 flex items-center gap-1"
                              title="تصدير كملف نصي"
                           >
                              TXT
                           </button>
                        </div>
                    </div>
                  </div>
                  <textarea 
                    value={activePage.extractedText}
                    onChange={(e) => updateText(activePage.id, e.target.value)}
                    className="flex-1 w-full p-6 resize-none focus:outline-none text-lg leading-loose font-serif"
                    dir="rtl"
                  ></textarea>
               </div>

               {/* Analysis Panel (Conditional) */}
               {analysisResult && (
                 <div className="w-1/3 border-r border-gray-200 bg-gray-50 flex flex-col">
                   <div className="p-3 border-b bg-white font-bold text-navy-900">التحليل الذكي</div>
                   <div className="p-4 overflow-y-auto text-sm space-y-2">
                     {analysisResult.split('\n').map((l, i) => <p key={i}>{l}</p>)}
                   </div>
                   <button onClick={() => setAnalysisResult('')} className="p-2 text-center text-xs text-red-500 hover:bg-red-50">إغلاق</button>
                 </div>
               )}
             </div>
           ) : (
             <div className="h-full flex flex-col items-center justify-center text-gray-400">
                <Eye className="w-16 h-16 mb-4 opacity-20" />
                <p>اختر عنصراً لعرض النص وتعديله</p>
             </div>
           )}
        </div>
      </div>

       {/* Hidden Print Area - Only visible during print */}
       <div id="print-area" className="hidden p-12 bg-white text-black">
          {activePage ? (
              <div dir="rtl" className="font-serif text-xl leading-loose whitespace-pre-wrap">
                  {activePage.extractedText}
              </div>
          ) : (
              <div className="text-center text-gray-500">لا يوجد نص للطباعة</div>
          )}
       </div>

    </div>
  );
};

export default OCRTool;

import { GoogleGenAI } from "@google/genai";
import { KUWAIT_LAWS_CONTEXT } from '../types';

// Helper to get authenticated client dynamically
const getGenAI = () => {
  const apiKey = process.env.API_KEY; 
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }
  return new GoogleGenAI({ apiKey });
};

// Draft a legal document
export const generateLegalDocument = async (
  docType: string,
  partyA: string,
  partyB: string,
  details: string,
  courtDetails?: { name: string; caseNumber: string; section: string }
): Promise<string> => {
  const ai = getGenAI();
  const courtContext = courtDetails ? `
    Court Name: ${courtDetails.name}
    Case Number: ${courtDetails.caseNumber}
    Department/Section: ${courtDetails.section}
    Include this court header information at the top of the document in a formal legal layout typical for Kuwaiti courts.
  ` : '';

  const prompt = `
    ${KUWAIT_LAWS_CONTEXT}

    Task: Draft a professional ${docType} in Arabic.

    ${courtContext}

    Parties:
    1. First Party: ${partyA}
    2. Second Party: ${partyB}

    Specific Details/Clauses to include:
    ${details}

    Format:
    - Use standard professional legal formatting suitable for Kuwaiti Courts.
    - Output ONLY the document text content.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { temperature: 0.3 }
    });
    return response.text || "حدث خطأ أثناء إنشاء المستند.";
  } catch (error) {
    console.error("Gen Doc Error:", error);
    return "عذراً، حدث خطأ في الاتصال بخدمة الذكاء الاصطناعي.";
  }
};

// Chat with Legal Assistant
export const sendLegalQuery = async (
  history: {role: string, parts: {text: string}[]}[],
  message: string
) => {
  try {
    const ai = getGenAI();
    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview',
      config: { systemInstruction: KUWAIT_LAWS_CONTEXT },
      history: history
    });

    const result = await chat.sendMessage({ message });
    return result.text;
  } catch (error) {
    console.error("Chat Error:", error);
    throw error;
  }
};

// OCR - Extract text from image (Enhanced for Handwriting)
export const extractTextFromImage = async (base64Image: string, highPrecision: boolean = false): Promise<string> => {
  try {
    const ai = getGenAI();
    // Use gemini-3-pro-image-preview (Nano Banana 3 Pro) for handwriting
    const modelName = highPrecision ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';

    const prompt = highPrecision 
      ? "You are an expert paleographer and legal clerk. Carefully transcribe the HANDWRITTEN Arabic text in this image. Focus on legal terminology, names, and dates. Preserve the exact layout and structure. If a word is illegible, mark it with [?]. Verbatim transcription ONLY."
      : "Extract all text from this legal document image exactly as it appears in Arabic. Preserve line breaks. Verbatim transcription ONLY.";

    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
          { text: prompt }
        ]
      }
    });
    return response.text || "";
  } catch (error) {
    console.error("OCR Error:", error);
    if (error instanceof Error && error.message.includes("entity was not found")) {
      return "ERROR_API_KEY_REQUIRED";
    }
    return "فشل استخراج النص من الصورة.";
  }
};

// Transcribe Audio
export const transcribeAudio = async (base64Audio: string): Promise<string> => {
  try {
    const ai = getGenAI();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-native-audio-preview-09-2025',
      contents: {
        parts: [
          { inlineData: { mimeType: 'audio/mp3', data: base64Audio } },
          { text: "Transcribe the following Arabic audio recording accurately into text. It is a legal context, so be precise." }
        ]
      }
    });
    return response.text || "";
  } catch (error) {
    console.error("Audio Transcription Error:", error);
    return "فشل تحويل الصوت إلى نص.";
  }
};

// Summarize/Analyze Document Text
export const analyzeLegalText = async (text: string): Promise<string> => {
  const prompt = `${KUWAIT_LAWS_CONTEXT}\nTask: Analyze the following legal text under Kuwaiti Law...\nText: ${text}`;
  try {
    const ai = getGenAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "";
  } catch (error) {
    console.error("Analysis Error:", error);
    return "فشل تحليل النص.";
  }
};

import React, { useState, useRef } from 'react';
import { extractTextFromImage, analyzeLegalText, transcribeAudio } from '../services/geminiService';
import { OcrPage } from '../types';
import { Upload, FileText, Trash2, Eye, BrainCircuit, Copy, Check, Printer, Camera, Mic, Square, Sparkles, AlertCircle } from 'lucide-react';

const OCRTool: React.FC = () => {
  const [pages, setPages] = useState<OcrPage[]>([]);
  const [selectedPageId, setSelectedPageId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const cameraInputRef = useRef<HTMLInputElement>(null);

  const [analyzing, setAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState('');
  const [copied, setCopied] = useState(false);
  const [highPrecision, setHighPrecision] = useState(true); // Default to true as per user request for quality

  // Audio Recording State
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files) {
      processFiles(Array.from(event.target.files));
    }
  };

  const processFiles = async (files: File[]) => {
    // If using high precision (Pro model), check for API key
    if (highPrecision && window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        alert("يتطلب وضع 'الدقة الفائقة' اختيار مفتاح API خاص بك (Project Paid). سيفتح الآن مربع الاختيار.");
        await window.aistudio.openSelectKey();
        // Proceeding anyway as per race condition rules
      }
    }

    for (const file of files) {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64Data = reader.result as string;
        const cleanBase64 = base64Data.split(',')[1];

        const newPage: OcrPage = {
          id: Date.now().toString() + Math.random().toString(),
          pageNumber: pages.length + 1,
          imageUrl: base64Data,
          extractedText: highPrecision ? "جاري المعالجة بنموذج Gemini 3 Pro لخط اليد..." : "جاري الاستخراج السريع...",
          isProcessing: true,
        };

        setPages(prev => [...prev, newPage]);
        if (!selectedPageId) setSelectedPageId(newPage.id);

        let text = await extractTextFromImage(cleanBase64, highPrecision);

        if (text === "ERROR_API_KEY_REQUIRED") {
            text = "خطأ: يتطلب هذا الوضع مفتاح API صالح. يرجى تفعيل مفتاحك من الإعدادات أو اختيار مفتاح الاستوديو.";
            if (window.aistudio) await window.aistudio.openSelectKey();
        }

        setPages(prev => prev.map(p => 
          p.id === newPage.id 
            ? { ...p, extractedText: text, isProcessing: false } 
            : p
        ));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleStartRecording = async () => {
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
      alert("المتصفح لا يدعم الوصول للميكروفون.");
      return;
    }
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];
      mediaRecorder.ondataavailable = (e) => e.data.size > 0 && audioChunksRef.current.push(e.data);
      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/mp3' });
        const reader = new FileReader();
        reader.onloadend = async () => {
          const base64String = (reader.result as string).split(',')[1];
          await processAudio(base64String);
        };
        reader.readAsDataURL(audioBlob);
        stream.getTracks().forEach(track => track.stop());
      };
      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      alert("تعذر الوصول للميكروفون.");
    }
  };

  const handleStopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const processAudio = async (base64Audio: string) => {
    const audioPlaceholder = "data:image/svg+xml;base64," + btoa(`<svg xmlns="http://www.w3.org/2000/svg" width="100" height="100" viewBox="0 0 24 24" fill="none" stroke="#d97706" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg>`);
    const newPage: OcrPage = {
      id: Date.now().toString() + Math.random().toString(),
      pageNumber: pages.length + 1,
      imageUrl: audioPlaceholder,
      extractedText: "جاري تحويل الصوت إلى نص...",
      isProcessing: true,
    };
    setPages(prev => [...prev, newPage]);
    if (!selectedPageId) setSelectedPageId(newPage.id);
    const text = await transcribeAudio(base64Audio);
    setPages(prev => prev.map(p => p.id === newPage.id ? { ...p, extractedText: text, isProcessing: false } : p));
  };

  const updateText = (id: string, newText: string) => setPages(prev => prev.map(p => p.id === id ? { ...p, extractedText: newText } : p));
  const removePage = (id: string) => {
    setPages(prev => prev.filter(p => p.id !== id));
    if (selectedPageId === id) setSelectedPageId(null);
  };

  const handleCopy = () => {
    const activePage = pages.find(p => p.id === selectedPageId);
    if (!activePage) return;
    navigator.clipboard.writeText(activePage.extractedText);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handlePrint = () => window.print();

  const handleExport = (format: 'doc' | 'txt') => {
    const activePage = pages.find(p => p.id === selectedPageId);
    if (!activePage) return;
    const blob = new Blob([activePage.extractedText], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `document_${Date.now()}.${format}`;
    a.click();
  };

  const handleAnalysis = async () => {
    if (!selectedPageId) return;
    const page = pages.find(p => p.id === selectedPageId);
    if (!page) return;
    setAnalyzing(true);
    const result = await analyzeLegalText(page.extractedText);
    setAnalysisResult(result);
    setAnalyzing(false);
  };

  const activePage = pages.find(p => p.id === selectedPageId);

  return (
    <div className="h-screen flex flex-col p-6 max-w-7xl mx-auto">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center mb-6 print:hidden gap-4">
        <div>
           <h2 className="text-2xl font-bold text-navy-900 flex items-center gap-2">
             المسح الذكي وقارئ خط اليد
             {highPrecision && <Sparkles className="w-5 h-5 text-gold-500 animate-pulse" />}
           </h2>
           <p className="text-gray-500 text-sm">نستخدم طاقة Gemini 3 Pro لفك رموز الخطوط اليدوية والمستندات القديمة.</p>
        </div>

        <div className="flex flex-wrap items-center gap-3">
            {/* Precision Toggle */}
            <div className="flex items-center gap-2 bg-gray-100 p-1.5 rounded-lg border border-gray-200">
               <button 
                  onClick={() => setHighPrecision(false)}
                  className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all ${!highPrecision ? 'bg-white shadow-sm text-navy-900' : 'text-gray-500 hover:text-gray-700'}`}
               >
                 مسح سريع
               </button>
               <button 
                  onClick={() => setHighPrecision(true)}
                  className={`px-3 py-1.5 rounded-md text-xs font-bold flex items-center gap-1 transition-all ${highPrecision ? 'bg-gold-500 text-white shadow-md' : 'text-gray-500 hover:text-gray-700'}`}
               >
                 <Sparkles className="w-3 h-3" />
                 دقة فائقة (خط يد)
               </button>
            </div>

            <div className="h-8 w-px bg-gray-300 hidden md:block"></div>

             <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 bg-navy-900 text-white px-4 py-2 rounded-lg hover:bg-navy-800 transition-colors">
              <Upload className="w-4 h-4" />
              <span>ملف</span>
            </button>
            <input type="file" multiple accept="image/*" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />

            <button onClick={() => cameraInputRef.current?.click()} className="flex items-center gap-2 bg-white text-navy-900 px-4 py-2 rounded-lg hover:bg-gray-50 transition-colors border border-gray-300">
              <Camera className="w-4 h-4" />
              <span>كاميرا</span>
            </button>
            <input type="file" accept="image/*" capture="environment" className="hidden" ref={cameraInputRef} onChange={handleFileUpload} />

            <button onClick={isRecording ? handleStopRecording : handleStartRecording} className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all border font-bold ${isRecording ? 'bg-red-50 text-red-600 border-red-200 animate-pulse' : 'bg-gold-50 text-gold-700 border-gold-200 hover:bg-gold-100'}`}>
              {isRecording ? <Square className="w-4 h-4 fill-current" /> : <Mic className="w-4 h-4" />}
              <span>{isRecording ? 'إيقاف' : 'بصوتى'}</span>
            </button>
        </div>
      </div>

      {highPrecision && (
          <div className="mb-4 bg-gold-50 border border-gold-200 p-2 rounded-lg flex items-center gap-2 text-xs text-gold-800 animate-fade-in">
              <AlertCircle className="w-4 h-4" />
              <span>وضع الدقة الفائقة نشط: سيتم استخدام موديل Gemini 3 Pro (Nano Banana 3 Pro) لضمان أعلى جودة في قراءة النصوص المكتوبة بخط اليد.</span>
          </div>
      )}

      <div className="flex flex-1 gap-6 overflow-hidden print:hidden">
        {/* Thumbnails Sidebar */}
        <div className="w-48 bg-gray-100 rounded-xl p-4 overflow-y-auto space-y-4 border border-gray-200 flex-shrink-0">
          <h3 className="text-xs font-bold text-gray-500 uppercase">المستندات</h3>
          {pages.length === 0 && <p className="text-xs text-gray-400 text-center mt-10">لا توجد عناصر</p>}
          {pages.map((page) => (
            <div key={page.id} onClick={() => setSelectedPageId(page.id)} className={`relative group cursor-pointer border-2 rounded-lg overflow-hidden transition-all bg-white ${selectedPageId === page.id ? 'border-gold-500 ring-2 ring-gold-200' : 'border-gray-200 hover:border-gray-300'}`}>
              <img src={page.imageUrl} alt={`Page ${page.pageNumber}`} className="w-full h-32 object-contain bg-gray-50" />
              <div className="absolute bottom-0 left-0 right-0 bg-black/60 text-white text-[10px] p-1 text-center">
                {page.imageUrl.includes('svg') ? 'تسجيل' : `صفحة ${page.pageNumber}`}
              </div>
              <button onClick={(e) => { e.stopPropagation(); removePage(page.id); }} className="absolute top-1 right-1 p-1 bg-red-500 text-white rounded opacity-0 group-hover:opacity-100 transition-opacity">
                <Trash2 className="w-3 h-3" />
              </button>
              {page.isProcessing && (
                <div className="absolute inset-0 bg-white/50 flex items-center justify-center">
                   <div className="animate-spin w-6 h-6 border-2 border-navy-900 border-t-transparent rounded-full"></div>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* Editor Area */}
        <div className="flex-1 bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col overflow-hidden">
           {activePage ? (
             <div className="flex h-full">
               <div className="flex-1 flex flex-col border-l border-gray-200">
                  <div className="p-3 bg-gray-50 border-b border-gray-200 flex flex-wrap justify-between items-center gap-2">
                    <div className="flex items-center gap-2">
                         <span className="font-bold text-gray-700 flex items-center gap-2">
                            <FileText className="w-4 h-4" /> النص المستخرج
                         </span>
                         <button onClick={handleAnalysis} disabled={analyzing} className="text-xs flex items-center gap-1 bg-gold-100 text-gold-700 px-2 py-1 rounded hover:bg-gold-200 ml-2">
                            <BrainCircuit className="w-3 h-3" />
                            {analyzing ? 'جاري التحليل...' : 'تحليل قانوني'}
                          </button>
                    </div>
                    <div className="flex items-center gap-2">
                        <button onClick={handleCopy} className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-gray-100 text-gray-600 hover:bg-gray-200 text-xs font-bold transition-all">
                            {copied ? <Check className="w-3.5 h-3.5 text-green-600" /> : <Copy className="w-3.5 h-3.5" />}
                            {copied ? 'تم' : 'نسخ'}
                        </button>
                        <button onClick={handlePrint} className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-gray-100 text-gray-600 hover:bg-gray-200 text-xs font-bold transition-all">
                            <Printer className="w-3.5 h-3.5" />
                            طباعة
                        </button>
                        <div className="w-px h-5 bg-gray-300 mx-1"></div>
                        <div className="flex bg-gray-100 rounded-lg p-0.5">
                           <button onClick={() => handleExport('doc')} className="px-2 py-1 rounded hover:bg-white text-[10px] font-bold text-gray-600">Word</button>
                           <button onClick={() => handleExport('txt')} className="px-2 py-1 rounded hover:bg-white text-[10px] font-bold text-gray-600">TXT</button>
                        </div>
                    </div>
                  </div>
                  <textarea value={activePage.extractedText} onChange={(e) => updateText(activePage.id, e.target.value)} className="flex-1 w-full p-8 resize-none focus:outline-none text-xl leading-relaxed font-serif" dir="rtl"></textarea>
               </div>
               {analysisResult && (
                 <div className="w-1/3 border-r border-gray-200 bg-gray-50 flex flex-col">
                   <div className="p-3 border-b bg-white font-bold text-navy-900">التحليل الذكي</div>
                   <div className="p-4 overflow-y-auto text-sm space-y-2">{analysisResult.split('\n').map((l, i) => <p key={i}>{l}</p>)}</div>
                   <button onClick={() => setAnalysisResult('')} className="p-2 text-center text-xs text-red-500 hover:bg-red-50">إغلاق</button>
                 </div>
               )}
             </div>
           ) : (
             <div className="h-full flex flex-col items-center justify-center text-gray-400">
                <Eye className="w-16 h-16 mb-4 opacity-20" />
                <p>اختر صفحة لبدء المعالجة الذكية</p>
             </div>
           )}
        </div>
      </div>

       <div id="print-area" className="hidden p-12 bg-white text-black">
          {activePage && <div dir="rtl" className="font-serif text-xl leading-loose whitespace-pre-wrap">{activePage.extractedText}</div>}
       </div>
    </div>
  );
};

export default OCRTool;

import { GoogleGenAI } from "@google/genai";
import { KUWAIT_LAWS_CONTEXT } from '../types';

// Helper to get authenticated client dynamically
const getGenAI = () => {
  const apiKey = process.env.API_KEY; 
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }
  return new GoogleGenAI({ apiKey });
};

// Draft a legal document
export const generateLegalDocument = async (
  docType: string,
  partyA: string,
  partyB: string,
  details: string,
  courtDetails?: { name: string; caseNumber: string; section: string }
): Promise<string> => {
  const ai = getGenAI();
  const courtContext = courtDetails ? `
    Court Name: ${courtDetails.name}
    Case Number: ${courtDetails.caseNumber}
    Department/Section: ${courtDetails.section}
    Include this court header information at the top of the document in a formal legal layout typical for Kuwaiti courts.
  ` : '';

  const prompt = `
    ${KUWAIT_LAWS_CONTEXT}

    Task: Draft a professional ${docType} in Arabic.

    ${courtContext}

    Parties:
    1. First Party: ${partyA}
    2. Second Party: ${partyB}

    Specific Details/Clauses to include:
    ${details}

    Format:
    - Use standard professional legal formatting suitable for Kuwaiti Courts.
    - Output ONLY the document text content.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { temperature: 0.3 }
    });
    return response.text || "حدث خطأ أثناء إنشاء المستند.";
  } catch (error) {
    console.error("Gen Doc Error:", error);
    return "عذراً، حدث خطأ في الاتصال بخدمة الذكاء الاصطناعي.";
  }
};

// Chat with Legal Assistant
export const sendLegalQuery = async (
  history: {role: string, parts: {text: string}[]}[],
  message: string
) => {
  try {
    const ai = getGenAI();
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview', // Switched from Pro to Flash
      config: { systemInstruction: KUWAIT_LAWS_CONTEXT },
      history: history
    });

    const result = await chat.sendMessage({ message });
    return result.text;
  } catch (error) {
    console.error("Chat Error:", error);
    throw error;
  }
};

// OCR - Extract text from image (Enhanced for Handwriting)
export const extractTextFromImage = async (base64Image: string, highPrecision: boolean = false): Promise<string> => {
  try {
    const ai = getGenAI();
    // Switched high precision from gemini-3-pro-image-preview to gemini-3-flash-preview
    const modelName = highPrecision ? 'gemini-3-flash-preview' : 'gemini-2.5-flash-image';

    const prompt = highPrecision 
      ? "You are an expert paleographer and legal clerk. Carefully transcribe the HANDWRITTEN Arabic text in this image. Focus on legal terminology, names, and dates. Preserve the exact layout and structure. If a word is illegible, mark it with [?]. Verbatim transcription ONLY."
      : "Extract all text from this legal document image exactly as it appears in Arabic. Preserve line breaks. Verbatim transcription ONLY.";

    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
          { text: prompt }
        ]
      }
    });
    return response.text || "";
  } catch (error) {
    console.error("OCR Error:", error);
    if (error instanceof Error && error.message.includes("entity was not found")) {
      return "ERROR_API_KEY_REQUIRED";
    }
    return "فشل استخراج النص من الصورة.";
  }
};

// Transcribe Audio
export const transcribeAudio = async (base64Audio: string): Promise<string> => {
  try {
    const ai = getGenAI();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-native-audio-preview-09-2025',
      contents: {
        parts: [
          { inlineData: { mimeType: 'audio/mp3', data: base64Audio } },
          { text: "Transcribe the following Arabic audio recording accurately into text. It is a legal context, so be precise." }
        ]
      }
    });
    return response.text || "";
  } catch (error) {
    console.error("Audio Transcription Error:", error);
    return "فشل تحويل الصوت إلى نص.";
  }
};

// Summarize/Analyze Document Text
export const analyzeLegalText = async (text: string): Promise<string> => {
  const prompt = `${KUWAIT_LAWS_CONTEXT}\nTask: Analyze the following legal text under Kuwaiti Law...\nText: ${text}`;
  try {
    const ai = getGenAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "";
  } catch (error) {
    console.error("Analysis Error:", error);
    return "فشل تحليل النص.";
  }
};

import React, { useState, useRef } from 'react';
import { extractTextFromImage, analyzeLegalText, transcribeAudio } from '../services/geminiService';
import { OcrPage } from '../types';
import { Upload, FileText, Trash2, Eye, BrainCircuit, Copy, Check, Printer, Camera, Mic, Square, Sparkles, AlertCircle } from 'lucide-react';

const OCRTool: React.FC = () => {
  const [pages, setPages] = useState<OcrPage[]>([]);
  const [selectedPageId, setSelectedPageId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const cameraInputRef = useRef<HTMLInputElement>(null);

  const [analyzing, setAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState('');
  const [copied, setCopied] = useState(false);
  const [highPrecision, setHighPrecision] = useState(true);

  // Audio Recording State
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files) {
      processFiles(Array.from(event.target.files));
    }
  };

  const processFiles = async (files: File[]) => {
    for (const file of files) {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64Data = reader.result as string;
        const cleanBase64 = base64Data.split(',')[1];

        const newPage: OcrPage = {
          id: Date.now().toString() + Math.random().toString(),
          pageNumber: pages.length + 1,
          imageUrl: base64Data,
          extractedText: highPrecision ? "جاري المعالجة بنموذج Gemini 3 Flash لخط اليد..." : "جاري الاستخراج السريع...",
          isProcessing: true,
        };

        setPages(prev => [...prev, newPage]);
        if (!selectedPageId) setSelectedPageId(newPage.id);

        let text = await extractTextFromImage(cleanBase64, highPrecision);

        if (text === "ERROR_API_KEY_REQUIRED") {
            text = "خطأ: يتطلب هذا الوضع مفتاح API صالح. يرجى تفعيل مفتاحك من الإعدادات أو اختيار مفتاح الاستوديو.";
            if (window.aistudio) await window.aistudio.openSelectKey();
        }

        setPages(prev => prev.map(p => 
          p.id === newPage.id 
            ? { ...p, extractedText: text, isProcessing: false } 
            : p
        ));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleStartRecording = async () => {
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
      alert("المتصفح لا يدعم الوصول للميكروفون.");
      return;
    }
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];
      mediaRecorder.ondataavailable = (e) => e.data.size > 0 && audioChunksRef.current.push(e.data);
      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/mp3' });
        const reader = new FileReader();
        reader.onloadend = async () => {
          const base64String = (reader.result as string).split(',')[1];
          await processAudio(base64String);
        };
        reader.readAsDataURL(audioBlob);
        stream.getTracks().forEach(track => track.stop());
      };
      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      alert("تعذر الوصول للميكروفون.");
    }
  };

  const handleStopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const processAudio = async (base64Audio: string) => {
    const audioPlaceholder = "data:image/svg+xml;base64," + btoa(`<svg xmlns="http://www.w3.org/2000/svg" width="100" height="100" viewBox="0 0 24 24" fill="none" stroke="#d97706" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg>`);
    const newPage: OcrPage = {
      id: Date.now().toString() + Math.random().toString(),
      pageNumber: pages.length + 1,
      imageUrl: audioPlaceholder,
      extractedText: "جاري تحويل الصوت إلى نص...",
      isProcessing: true,
    };
    setPages(prev => [...prev, newPage]);
    if (!selectedPageId) setSelectedPageId(newPage.id);
    const text = await transcribeAudio(base64Audio);
    setPages(prev => prev.map(p => p.id === newPage.id ? { ...p, extractedText: text, isProcessing: false } : p));
  };

  const updateText = (id: string, newText: string) => setPages(prev => prev.map(p => p.id === id ? { ...p, extractedText: newText } : p));
  const removePage = (id: string) => {
    setPages(prev => prev.filter(p => p.id !== id));
    if (selectedPageId === id) setSelectedPageId(null);
  };

  const handleCopy = () => {
    const activePage = pages.find(p => p.id === selectedPageId);
    if (!activePage) return;
    navigator.clipboard.writeText(activePage.extractedText);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handlePrint = () => window.print();

  const handleExport = (format: 'doc' | 'txt') => {
    const activePage = pages.find(p => p.id === selectedPageId);
    if (!activePage) return;
    const blob = new Blob([activePage.extractedText], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `document_${Date.now()}.${format}`;
    a.click();
  };

  const handleAnalysis = async () => {
    if (!selectedPageId) return;
    const page = pages.find(p => p.id === selectedPageId);
    if (!page) return;
    setAnalyzing(true);
    const result = await analyzeLegalText(page.extractedText);
    setAnalysisResult(result);
    setAnalyzing(false);
  };

  const activePage = pages.find(p => p.id === selectedPageId);

  return (
    <div className="h-screen flex flex-col p-6 max-w-7xl mx-auto">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center mb-6 print:hidden gap-4">
        <div>
           <h2 className="text-2xl font-bold text-navy-900 flex items-center gap-2">
             المسح الذكي وقارئ خط اليد
             {highPrecision && <Sparkles className="w-5 h-5 text-gold-500 animate-pulse" />}
           </h2>
           <p className="text-gray-500 text-sm">نستخدم طاقة Gemini 3 Flash لفك رموز الخطوط اليدوية والمستندات بدقة عالية.</p>
        </div>

        <div className="flex flex-wrap items-center gap-3">
            <div className="flex items-center gap-2 bg-gray-100 p-1.5 rounded-lg border border-gray-200">
               <button 
                  onClick={() => setHighPrecision(false)}
                  className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all ${!highPrecision ? 'bg-white shadow-sm text-navy-900' : 'text-gray-500 hover:text-gray-700'}`}
               >
                 مسح سريع
               </button>
               <button 
                  onClick={() => setHighPrecision(true)}
                  className={`px-3 py-1.5 rounded-md text-xs font-bold flex items-center gap-1 transition-all ${highPrecision ? 'bg-gold-500 text-white shadow-md' : 'text-gray-500 hover:text-gray-700'}`}
               >
                 <Sparkles className="w-3 h-3" />
                 دقة فائقة (Flash 3)
               </button>
            </div>

            <div className="h-8 w-px bg-gray-300 hidden md:block"></div>

             <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 bg-navy-900 text-white px-4 py-2 rounded-lg hover:bg-navy-800 transition-colors">
              <Upload className="w-4 h-4" />
              <span>ملف</span>
            </button>
            <input type="file" multiple accept="image/*" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />

            <button onClick={() => cameraInputRef.current?.click()} className="flex items-center gap-2 bg-white text-navy-900 px-4 py-2 rounded-lg hover:bg-gray-50 transition-colors border border-gray-300">
              <Camera className="w-4 h-4" />
              <span>كاميرا</span>
            </button>
            <input type="file" accept="image/*" capture="environment" className="hidden" ref={cameraInputRef} onChange={handleFileUpload} />

            <button onClick={isRecording ? handleStopRecording : handleStartRecording} className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all border font-bold ${isRecording ? 'bg-red-50 text-red-600 border-red-200 animate-pulse' : 'bg-gold-50 text-gold-700 border-gold-200 hover:bg-gold-100'}`}>
              {isRecording ? <Square className="w-4 h-4 fill-current" /> : <Mic className="w-4 h-4" />}
              <span>{isRecording ? 'إيقاف' : 'بصوتى'}</span>
            </button>
        </div>
      </div>

      {highPrecision && (
          <div className="mb-4 bg-gold-50 border border-gold-200 p-2 rounded-lg flex items-center gap-2 text-xs text-gold-800 animate-fade-in">
              <AlertCircle className="w-4 h-4" />
              <span>وضع الدقة الفائقة نشط: يتم استخدام موديل Gemini 3 Flash لضمان أداء سريع وقراءة دقيقة للنصوص المكتوبة بخط اليد.</span>
          </div>
      )}

      <div className="flex flex-1 gap-6 overflow-hidden print:hidden">
        {/* Thumbnails Sidebar */}
        <div className="w-48 bg-gray-100 rounded-xl p-4 overflow-y-auto space-y-4 border border-gray-200 flex-shrink-0">
          <h3 className="text-xs font-bold text-gray-500 uppercase">المستندات</h3>
          {pages.length === 0 && <p className="text-xs text-gray-400 text-center mt-10">لا توجد عناصر</p>}
          {pages.map((page) => (
            <div key={page.id} onClick={() => setSelectedPageId(page.id)} className={`relative group cursor-pointer border-2 rounded-lg overflow-hidden transition-all bg-white ${selectedPageId === page.id ? 'border-gold-500 ring-2 ring-gold-200' : 'border-gray-200 hover:border-gray-300'}`}>
              <img src={page.imageUrl} alt={`Page ${page.pageNumber}`} className="w-full h-32 object-contain bg-gray-50" />
              <div className="absolute bottom-0 left-0 right-0 bg-black/60 text-white text-[10px] p-1 text-center">
                {page.imageUrl.includes('svg') ? 'تسجيل' : `صفحة ${page.pageNumber}`}
              </div>
              <button onClick={(e) => { e.stopPropagation(); removePage(page.id); }} className="absolute top-1 right-1 p-1 bg-red-500 text-white rounded opacity-0 group-hover:opacity-100 transition-opacity">
                <Trash2 className="w-3 h-3" />
              </button>
              {page.isProcessing && (
                <div className="absolute inset-0 bg-white/50 flex items-center justify-center">
                   <div className="animate-spin w-6 h-6 border-2 border-navy-900 border-t-transparent rounded-full"></div>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* Editor Area */}
        <div className="flex-1 bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col overflow-hidden">
           {activePage ? (
             <div className="flex h-full">
               <div className="flex-1 flex flex-col border-l border-gray-200">
                  <div className="p-3 bg-gray-50 border-b border-gray-200 flex flex-wrap justify-between items-center gap-2">
                    <div className="flex items-center gap-2">
                         <span className="font-bold text-gray-700 flex items-center gap-2">
                            <FileText className="w-4 h-4" /> النص المستخرج
                         </span>
                         <button onClick={handleAnalysis} disabled={analyzing} className="text-xs flex items-center gap-1 bg-gold-100 text-gold-700 px-2 py-1 rounded hover:bg-gold-200 ml-2">
                            <BrainCircuit className="w-3 h-3" />
                            {analyzing ? 'جاري التحليل...' : 'تحليل قانوني'}
                          </button>
                    </div>
                    <div className="flex items-center gap-2">
                        <button onClick={handleCopy} className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-gray-100 text-gray-600 hover:bg-gray-200 text-xs font-bold transition-all">
                            {copied ? <Check className="w-3.5 h-3.5 text-green-600" /> : <Copy className="w-3.5 h-3.5" />}
                            {copied ? 'تم' : 'نسخ'}
                        </button>
                        <button onClick={handlePrint} className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-gray-100 text-gray-600 hover:bg-gray-200 text-xs font-bold transition-all">
                            <Printer className="w-3.5 h-3.5" />
                            طباعة
                        </button>
                        <div className="w-px h-5 bg-gray-300 mx-1"></div>
                        <div className="flex bg-gray-100 rounded-lg p-0.5">
                           <button onClick={() => handleExport('doc')} className="px-2 py-1 rounded hover:bg-white text-[10px] font-bold text-gray-600">Word</button>
                           <button onClick={() => handleExport('txt')} className="px-2 py-1 rounded hover:bg-white text-[10px] font-bold text-gray-600">TXT</button>
                        </div>
                    </div>
                  </div>
                  <textarea value={activePage.extractedText} onChange={(e) => updateText(activePage.id, e.target.value)} className="flex-1 w-full p-8 resize-none focus:outline-none text-xl leading-relaxed font-serif" dir="rtl"></textarea>
               </div>
               {analysisResult && (
                 <div className="w-1/3 border-r border-gray-200 bg-gray-50 flex flex-col">
                   <div className="p-3 border-b bg-white font-bold text-navy-900">التحليل الذكي</div>
                   <div className="p-4 overflow-y-auto text-sm space-y-2">{analysisResult.split('\n').map((l, i) => <p key={i}>{l}</p>)}</div>
                   <button onClick={() => setAnalysisResult('')} className="p-2 text-center text-xs text-red-500 hover:bg-red-50">إغلاق</button>
                 </div>
               )}
             </div>
           ) : (
             <div className="h-full flex flex-col items-center justify-center text-gray-400">
                <Eye className="w-16 h-16 mb-4 opacity-20" />
                <p>اختر صفحة لبدء المعالجة الذكية</p>
             </div>
           )}
        </div>
      </div>

       <div id="print-area" className="hidden p-12 bg-white text-black">
          {activePage && <div dir="rtl" className="font-serif text-xl leading-loose whitespace-pre-wrap">{activePage.extractedText}</div>}
       </div>
    </div>
  );
};

